import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getAcquisitionSignals(chainName, protocolTreasury) {
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    chainName, protocolTreasury, { pageSize: 50 }
  );
  const largeOutflows = (txns.data?.items ?? []).filter(tx => (tx.value_quote ?? 0) > 100000);
  return { largeOutflows, signalCount: largeOutflows.length };
}
